                Pattern.compile("<meta[^>]*name=[\"']description[\"'][^>]*content=[\"'](.*?)[\"'][^>]*>", Pattern.CASE_INSENSITIVE | Pattern.DOTALL),
                Pattern.compile("<meta[^>]*content=[\"'](.*?)[\"'][^>]*name=[\"']description[\"'][^>]*>", Pattern.CASE_INSENSITIVE | Pattern.DOTALL),
                Pattern.compile("<meta[^>]*property=[\"']og:description[\"'][^>]*content=[\"'](.*?)[\"'][^>]*>", Pattern.CASE_INSENSITIVE | Pattern.DOTALL),
                Pattern.compile("<meta[^>]*content=[\"'](.*?)[\"'][^>]*property=[\"']og:description[\"'][^>]*>", Pattern.CASE_INSENSITIVE | Pattern.DOTALL)
        };

        for (Pattern pattern : patterns) {
            Matcher matcher = pattern.matcher(html);
            if (matcher.find()) {
                return cleanText(matcher.group(1));
            }
        }
        return "";
    }

    private String fallbackDescription(String html) {
        String text = html.replaceAll("(?is)<script.*?>.*?</script>", " ")
                .replaceAll("(?is)<style.*?>.*?</style>", " ")
                .replaceAll("(?is)<[^>]+>", " ")
                .replaceAll("&nbsp;", " ")
                .replaceAll("&amp;", "&")
                .replaceAll("\\s+", " ")
                .trim();

        if (text.length() > 200) {
            return text.substring(0, 200);
        }
        return text;
    }

    private String cleanText(String text) {
        if (text == null) {
            return "";
        }
        return text.replaceAll("(?is)<[^>]+>", " ")
                .replaceAll("&nbsp;", " ")
                .replaceAll("&amp;", "&")
                .replaceAll("&quot;", "\"")
                .replaceAll("&#39;", "'")
                .replaceAll("\\s+", " ")
                .trim();
    }

    private String buildPreview(String title, String description) {
        return "Title: " + (title == null ? "" : title) + "\nDescription: " + (description == null ? "" : description);
    }
